// ============================================================
// Parse JotForm Premium Data v1
// Inherits all standard fields + premium booking/CRM fields
// ============================================================

const rawBody = $input.first().json.body;
const formData = (rawBody && rawBody.body) ? rawBody.body : rawBody;

function normalizeList(val) {
  if (!val) return '';
  if (Array.isArray(val)) return val.filter(Boolean).join(', ');
  return String(val).trim();
}

function clean(val, fallback = '') {
  if (!val) return fallback;
  return String(val).trim() || fallback;
}

const extractedData = {
  stripe_customer_id: clean(formData.stripe_customer_id || formData['stripe_customer_id']),

  // Section 1: Business Information (same as standard)
  company_name:         clean(formData.q4_hvacCompany || formData['q4_hvacCompany']),
  owner_name:           clean(formData.q54_ownerName || formData['q54_ownerName']),
  main_phone:           clean(formData.q6_mainCompany || formData['q6_mainCompany']),
  client_email:         clean(formData.q5_emailAddress || formData['q5_emailAddress']),
  website:              clean(formData.q7_companyWebsite || formData['q7_companyWebsite']),
  years_in_business:    clean(formData.q8_yearsIn || formData['q8_yearsIn']),
  timezone:             clean(formData.q34_timezone || formData['q34_timezone'], 'America/Chicago'),
  services_offered:     normalizeList(formData.q13_servicesOffered || formData['q13_servicesOffered']),
  brands_serviced:      normalizeList(formData.q14_brandsequipmentServiced || formData['q14_brandsequipmentServiced']),
  service_area:         clean(formData.q16_primaryService || formData['q16_primaryService']),
  service_area_radius:  clean(formData.q40_serviceAreaRadius || formData['q40_serviceAreaRadius']),
  certifications:       normalizeList(formData.q29_certifications || formData['q29_certifications']),
  licensed_insured:     clean(formData.q28_licensedAnd || formData['q28_licensedAnd'], 'Yes'),

  // Section 2: AI Receptionist Configuration
  agent_name:           clean(formData.q10_aiAgent10 || formData['q10_aiAgent10']),
  voice_gender:         clean(formData.q11_aiVoice || formData['q11_aiVoice'], 'Female'),
  custom_greeting:      clean(formData.q38_customGreeting || formData['q38_customGreeting']),
  company_tagline:      clean(formData.q39_companyTagline || formData['q39_companyTagline']),
  business_hours:       clean(formData.q17_businessHours || formData['q17_businessHours']),
  response_time:        clean(formData.q18_typicalResponse || formData['q18_typicalResponse']),
  emergency_service:    clean(formData.q20_247Emergency || formData['q20_247Emergency'], 'No'),
  emergency_phone:      clean(formData.q21_emergencyAfterhours || formData['q21_emergencyAfterhours']),
  after_hours_behavior: clean(formData.q22_afterhoursBehavior || formData['q22_afterhoursBehavior']),

  // Section 3: Call Handling & Pricing
  pricing_policy:       clean(formData.q42_pricingPolicy || formData['q42_pricingPolicy'], 'We provide free quotes on-site'),
  diagnostic_fee:       clean(formData.q41_diagnosticFee || formData['q41_diagnosticFee']),
  standard_fees:        clean(formData.q43_standardFees || formData['q43_standardFees']),
  free_estimates:       clean(formData.q24_freeEstimates || formData['q24_freeEstimates'], 'Yes - always free'),
  do_not_service:       clean(formData.q57_doNotServiceList || formData['q57_doNotServiceList']),
  transfer_phone:       clean(formData.q48_transferPhone || formData['q48_transferPhone']),
  transfer_triggers:    normalizeList(formData.q49_transferTriggers || formData['q49_transferTriggers']),
  transfer_behavior:    clean(formData.q50_transferBehavior || formData['q50_transferBehavior'], 'Try once - take message if no answer'),

  // Section 4: Notifications
  lead_contact_method:  clean(formData.q31_leadContact || formData['q31_leadContact'], 'Both'),
  lead_phone:           clean(formData.q32_leadNotification || formData['q32_leadNotification']),
  lead_email:           clean(formData.q33_leadNotification33 || formData['q33_leadNotification33']),
  notification_email_2: clean(formData.q59_notifEmail2 || formData['q59_notifEmail2']),
  notification_email_3: clean(formData.q60_notifEmail3 || formData['q60_notifEmail3']),
  notification_sms_2:   clean(formData.q61_notifSms2 || formData['q61_notifSms2']),
  notification_sms_3:   clean(formData.q62_notifSms3 || formData['q62_notifSms3']),

  // Section 5: Branding & Promotions
  google_review_rating:  clean(formData.q55_googleReviewRating || formData['q55_googleReviewRating']),
  google_review_count:   clean(formData.q56_googleReviewCount || formData['q56_googleReviewCount']),
  unique_selling_points: clean(formData.q51_uniqueSellingPoints || formData['q51_uniqueSellingPoints']),
  current_promotion:     clean(formData.q52_currentPromotion || formData['q52_currentPromotion']),
  seasonal_services:     clean(formData.q53_seasonalServices || formData['q53_seasonalServices']),
  membership_program:    clean(formData.q58_membershipProgramName || formData['q58_membershipProgramName']),
  maintenance_plans:     clean(formData.q46_maintenancePlans || formData['q46_maintenancePlans'], 'No'),
  financing_available:   clean(formData.q25_financingAvailable || formData['q25_financingAvailable'], 'No'),
  financing_details:     clean(formData.q44_financingDetails || formData['q44_financingDetails']),
  warranty:              clean(formData.q26_serviceWarranties || formData['q26_serviceWarranties'], 'Yes'),
  warranty_details:      clean(formData.q27_warrantyDetails || formData['q27_warrantyDetails']),
  payment_methods:       normalizeList(formData.q45_paymentMethods || formData['q45_paymentMethods']),
  additional_info:       clean(formData.q37_additionalInfo || formData['q37_additionalInfo']),

  // ── Section 6: Booking & Integration (PREMIUM ONLY) ───────
  crm_platform:            clean(formData.q70_crmPlatform || formData['q70_crmPlatform']),
  calendar_platform:       clean(formData.q71_calendarPlatform || formData['q71_calendarPlatform']),
  booking_slot_duration:   clean(formData.q72_slotDuration || formData['q72_slotDuration'], '60'),
  booking_lead_time:       clean(formData.q73_bookingLeadTime || formData['q73_bookingLeadTime'], '2'),
  bookable_job_types:      normalizeList(formData.q74_bookableJobTypes || formData['q74_bookableJobTypes']),
  booking_confirm_method:  clean(formData.q75_bookingConfirm || formData['q75_bookingConfirm'], 'email'),
  available_time_slots:    clean(formData.q76_availableTimeSlots || formData['q76_availableTimeSlots'], 'Morning (8am-12pm), Afternoon (12pm-5pm)'),
  booking_buffer_minutes:  clean(formData.q77_bufferMinutes || formData['q77_bufferMinutes'], '30'),
  calendar_api_key:        clean(formData.q78_calendarApiKey || formData['q78_calendarApiKey']),
  crm_api_key:             clean(formData.q79_crmApiKey || formData['q79_crmApiKey']),
  calendar_resource_id:    clean(formData.q80_calendarResourceId || formData['q80_calendarResourceId']),

  // Meta
  industry_type: 'HVAC',
  tier: 'premium',
  after_hours_transfer: clean(formData.q63_afterHoursTransfer || formData['q63_afterHoursTransfer'], 'all')
};

// Build company info block
let companyInfoBlock = `## Company Overview
`;
companyInfoBlock += `- Company Name: ${extractedData.company_name}
`;
if (extractedData.main_phone) companyInfoBlock += `- Main Phone: ${extractedData.main_phone}
`;
if (extractedData.years_in_business) companyInfoBlock += `- Experience: ${extractedData.years_in_business} years in business
`;
if (extractedData.owner_name) companyInfoBlock += `- Owner/Manager: ${extractedData.owner_name}
`;
if (extractedData.company_tagline) companyInfoBlock += `- Tagline: ${extractedData.company_tagline}
`;
if (extractedData.website) companyInfoBlock += `- Website: ${extractedData.website}
`;
companyInfoBlock += `- Licensed & Insured: ${extractedData.licensed_insured}
`;
if (extractedData.certifications) companyInfoBlock += `- Certifications: ${extractedData.certifications}
`;

companyInfoBlock += `
## Services
`;
if (extractedData.services_offered) companyInfoBlock += `- Services: ${extractedData.services_offered}
`;
if (extractedData.brands_serviced) companyInfoBlock += `- Brands Serviced: ${extractedData.brands_serviced}
`;
if (extractedData.service_area) {
  let areaLine = extractedData.service_area;
  if (extractedData.service_area_radius) areaLine += ` (within ${extractedData.service_area_radius})`;
  companyInfoBlock += `- Service Area: ${areaLine}
`;
}

companyInfoBlock += `
## Hours & Availability
`;
if (extractedData.business_hours) companyInfoBlock += `- Business Hours: ${extractedData.business_hours}
`;
if (extractedData.response_time) companyInfoBlock += `- Typical Response Time: ${extractedData.response_time}
`;
companyInfoBlock += `- 24/7 Emergency Service: ${extractedData.emergency_service}
`;

companyInfoBlock += `
## Booking
`;
if (extractedData.calendar_platform) companyInfoBlock += `- Calendar System: ${extractedData.calendar_platform}
`;
if (extractedData.available_time_slots) companyInfoBlock += `- Available Time Windows: ${extractedData.available_time_slots}
`;
if (extractedData.bookable_job_types) companyInfoBlock += `- Bookable Services: ${extractedData.bookable_job_types}
`;
if (extractedData.booking_confirm_method) companyInfoBlock += `- Booking Confirmations sent via: ${extractedData.booking_confirm_method}
`;

extractedData.companyInfoBlock = companyInfoBlock;
return extractedData;

// Premium Prompt Builder — pass-through
// The actual prompt-builder-premium.js logic runs here (copy from GitHub file)
// This node reads from Parse JotForm Premium Data and outputs conversationFlow + agentConfig
// IMPORTANT: Paste full contents of hvac-premium/prompt-builder-premium.js into this node

// Placeholder — replace this comment block with the full prompt-builder-premium.js content
const data = $input.first().json;
return { ...data, _note: 'Replace this node body with prompt-builder-premium.js contents' };

const flowResponse = $input.first().json;
const builderData = $('Build Premium Prompt + Flow').first().json;

const llmId = flowResponse.llm_id;
if (!llmId) throw new Error('No llm_id returned from Retell flow creation: ' + JSON.stringify(flowResponse));

const agentConfig = builderData.agentConfig;

return {
  ...builderData,
  llm_id: llmId,
  agentPayload: {
    ...agentConfig,
    response_engine: { type: 'retell-llm', llm_id: llmId }
  }
};

const agentResponse = $input.first().json;
const previousData = $('Build Agent Payload').first().json;

const agentId = agentResponse.agent_id;
if (!agentId) throw new Error('No agent_id returned from Retell agent creation: ' + JSON.stringify(agentResponse));

return {
  ...previousData,
  agent_id: agentId,
  llm_id: previousData.llm_id,
  company_name: previousData.companyName,
  agent_name: previousData.agentName
};
